using namespace std;

string solve(string s) {
    string result;
    for (char c : s) {
        if (islower(c)) {
            result += c;
        } else if (c == '*') {
            if (!result.empty()) {
                result.pop_back();
            }
        } else if (c == '#') {
            result += result;
        } else if (c == '%') {
            reverse(result.begin(), result.end());
        }
    }
    return result;
}

